create table if not exists requests (id uuid primary key default gen_random_uuid(), status text not null default 'new', payload jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists quotes (id uuid primary key default gen_random_uuid(), request_id uuid, status text not null default 'draft', payload jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists work_orders (id uuid primary key default gen_random_uuid(), quote_id uuid, status text not null default 'scheduled', assigned_to uuid, payload jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists invoices (id uuid primary key default gen_random_uuid(), work_order_id uuid, status text not null default 'draft', amount_cents integer not null default 0, square_payment_url text, payload jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists payments (id uuid primary key default gen_random_uuid(), invoice_id uuid, provider text not null default 'square', status text not null default 'pending', amount_cents integer not null default 0, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
